SELECT COUNT(version_id) AS version_count
FROM annotation_versions
WHERE annotation_id = 0;

SELECT access_level, MAX(text_version) AS max_version
FROM texts
WHERE access_level = 'public';

SELECT review_status, review_comments
FROM review_logs
WHERE review_status = 'rejected';

SELECT COUNT(*) AS approved_annotation_count
FROM review_logs
WHERE review_status = 'approved';

SELECT version_number, version_text, confidence_score
FROM annotation_versions
WHERE annotation_id = 0;
